import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"How It Works","description":"The indexing model, storage layout, scan lifecycle, and feed logic behind Foldergram.","frontmatter":{"title":"How It Works","description":"The indexing model, storage layout, scan lifecycle, and feed logic behind Foldergram."},"headers":[],"relativePath":"how-it-works.md","filePath":"how-it-works.md","lastUpdated":1775244546000}'),s={name:"how-it-works.md"};function o(d,e,l,n,c,h){return t(),r("div",null,[...e[0]||(e[0]=[i(`<h1 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h1><h2 id="architecture-at-a-glance" tabindex="-1">Architecture at a glance <a class="header-anchor" href="#architecture-at-a-glance" aria-label="Permalink to &quot;Architecture at a glance&quot;">​</a></h2><p>Foldergram has two deliberate layers:</p><ol><li>A scanner/indexer that walks the gallery tree, updates SQLite, and generates derivatives.</li><li>A runtime API and SPA that read indexed data from SQLite and serve static derivative assets.</li></ol><p>That separation is the core performance decision in the project.</p><h2 id="source-discovery-model" tabindex="-1">Source discovery model <a class="header-anchor" href="#source-discovery-model" aria-label="Permalink to &quot;Source discovery model&quot;">​</a></h2><p>Foldergram recursively walks <code>GALLERY_ROOT</code> and applies these rules:</p><ul><li>Hidden paths are skipped.</li><li>Managed storage paths under the gallery root are skipped.</li><li>Folder exclusions from <code>GALLERY_EXCLUDED_FOLDERS</code> and saved <code>General Settings</code> rules are skipped.</li><li>Any non-hidden folder that directly contains supported media becomes an indexed album.</li><li>Files directly in <code>GALLERY_ROOT</code> are ignored.</li><li>Nested folders are treated separately from their parent folders.</li><li>In the default reserved-stories mode, a child <code>stories/</code> folder beneath an indexed owner folder is withheld from normal album discovery and scanned separately as story data.</li></ul><h2 id="reserved-stories-folders" tabindex="-1">Reserved stories folders <a class="header-anchor" href="#reserved-stories-folders" aria-label="Permalink to &quot;Reserved stories folders&quot;">​</a></h2><p>By default, Foldergram treats <code>AppFolder/stories</code> as a reserved subtree for that app folder.</p><p>The scan model is:</p><ul><li>direct media inside <code>AppFolder/stories</code> becomes a <code>story_root</code> folder used for the avatar story set</li><li>each direct child directory under <code>AppFolder/stories</code> becomes one <code>story_capsule</code></li><li>nested media below that direct child directory is collected recursively into the same capsule</li><li>reserved story folders do not become normal app folders while this mode is enabled</li><li>if the reserved root has no direct media but highlight capsules exist, Foldergram synthesizes an avatar-story entry from recent highlight media</li></ul><p>This behavior is controlled by the Settings toggle <code>Treat stories folders as normal app folders</code>. When that legacy mode is enabled, <code>stories/</code> folders are discovered like ordinary app folders again.</p><h2 id="excluded-folders" tabindex="-1">Excluded folders <a class="header-anchor" href="#excluded-folders" aria-label="Permalink to &quot;Excluded folders&quot;">​</a></h2><p>Foldergram merges exclusion rules from:</p><ul><li><code>GALLERY_EXCLUDED_FOLDERS</code></li><li>custom rules saved from <code>Settings -&gt; General Settings</code></li></ul><p>Rule semantics are intentionally simple:</p><ul><li>values without a slash match folder names anywhere in the gallery tree</li><li>values with a slash match one exact relative path below <code>GALLERY_ROOT</code></li></ul><p>Excluded folders are skipped during startup scans, rescans, and watcher-driven discovery work. Changing the saved runtime rules updates <code>app_settings</code> immediately, but a follow-up scan from <code>Settings -&gt; Scan &amp; Library</code> is still required so already-indexed matches can be soft-removed from the library.</p><h2 id="storage-layout" tabindex="-1">Storage layout <a class="header-anchor" href="#storage-layout" aria-label="Permalink to &quot;Storage layout&quot;">​</a></h2><p>By default the app uses:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data/</span></span>
<span class="line"><span>  gallery/       # originals</span></span>
<span class="line"><span>  db/</span></span>
<span class="line"><span>    gallery.sqlite</span></span>
<span class="line"><span>  thumbnails/    # asset-key-sharded thumbnail derivatives</span></span>
<span class="line"><span>  previews/      # asset-key-sharded preview derivatives</span></span></code></pre></div><p>The database schema includes:</p><ul><li><code>folders</code></li><li><code>images</code></li><li><code>scan_runs</code></li><li><code>app_settings</code></li><li><code>folder_scan_state</code></li><li><code>likes</code></li></ul><h2 id="what-is-stored-per-indexed-post" tabindex="-1">What is stored per indexed post <a class="header-anchor" href="#what-is-stored-per-indexed-post" aria-label="Permalink to &quot;What is stored per indexed post&quot;">​</a></h2><p>The <code>images</code> table stores:</p><ul><li>a stable <code>asset_key</code> used for derivative storage</li><li>normalized relative and absolute paths</li><li>file size and <code>mtime_ms</code></li><li>width and height</li><li>media type and MIME type</li><li>duration for videos</li><li>a fingerprint built from <code>relative_path + file_size + mtime_ms</code></li><li><code>sort_timestamp</code></li><li><code>taken_at</code> and <code>taken_at_source</code></li><li>stored derivative paths</li><li>playback strategy for videos</li><li>soft-delete state including <code>deleted_at</code></li></ul><h2 id="stable-ordering" tabindex="-1">Stable ordering <a class="header-anchor" href="#stable-ordering" aria-label="Permalink to &quot;Stable ordering&quot;">​</a></h2><p>Foldergram preserves stable sort order across rescans.</p><p>If a file already exists in the database, the scanner keeps its prior <code>sort_timestamp</code>. If not, it falls back to:</p><ol><li>the existing <code>first_seen_at</code>, if present</li><li>the current file <code>mtime_ms</code></li></ol><p>That prevents older posts from jumping around every time the library is rescanned.</p><h2 id="soft-delete-and-reactivation" tabindex="-1">Soft delete and reactivation <a class="header-anchor" href="#soft-delete-and-reactivation" aria-label="Permalink to &quot;Soft delete and reactivation&quot;">​</a></h2><p>Foldergram does not hard-delete missing indexed files during scans.</p><p>Instead it:</p><ul><li>marks missing files as <code>is_deleted = 1</code></li><li>records <code>deleted_at</code></li><li>keeps their historical row data</li><li>reactivates them if the same relative path reappears later</li></ul><p>Direct user-triggered delete actions are different. Those remove the source file and derivatives first, then mark or remove the indexed records as part of the delete flow.</p><h2 id="folder-shortcuts-during-scans" tabindex="-1">Folder shortcuts during scans <a class="header-anchor" href="#folder-shortcuts-during-scans" aria-label="Permalink to &quot;Folder shortcuts during scans&quot;">​</a></h2><p>To avoid unnecessary work, Foldergram records per-folder scan signatures in <code>folder_scan_state</code>. If a folder signature still matches and metadata coverage is complete, the scanner can skip reprocessing every file in that folder.</p><p>That shortcut is bypassed when Foldergram needs to repair unchanged derivatives or when gallery-root assumptions no longer match.</p><h2 id="full-scan-lifecycle" tabindex="-1">Full scan lifecycle <a class="header-anchor" href="#full-scan-lifecycle" aria-label="Permalink to &quot;Full scan lifecycle&quot;">​</a></h2><p>During a full scan, Foldergram:</p><ol><li>Walks the gallery tree to discover source folders.</li><li>Stats supported files in those folders.</li><li>Resolves folder records and stable slugs.</li><li>Scans reserved <code>stories/</code> subtrees for owner folders when reserved-stories mode is active.</li><li>Reads or refreshes media metadata.</li><li>Reconciles eligible file moves so the same row, likes, and derivative paths can survive path changes.</li><li>Marks missing indexed rows as deleted.</li><li>Queues derivative work for changed or missing outputs.</li><li>Performs deferred stale-derivative cleanup after successful scans.</li><li>Writes scan status to <code>scan_runs</code>.</li></ol><h2 id="scan-progress-phases" tabindex="-1">Scan progress phases <a class="header-anchor" href="#scan-progress-phases" aria-label="Permalink to &quot;Scan progress phases&quot;">​</a></h2><p>Foldergram reports long-running scans in three phases:</p><ul><li><code>migration</code> checks previously indexed rows, backfills missing <code>asset_key</code> values, and moves, repairs, or regenerates legacy derivatives before fresh indexing begins</li><li><code>discovery</code> walks the gallery tree, resolves folders, refreshes metadata, and reconciles safe file moves</li><li><code>derivatives</code> processes queued thumbnail and preview jobs after discovery has identified the required work</li></ul><p>Only migration and derivative work have a fixed total upfront. Discovery still reports discovered and processed folder and post counts, but the client keeps that phase indeterminate because the final discovery total can keep growing while more folders are found.</p><h2 id="incremental-scans-and-watching" tabindex="-1">Incremental scans and watching <a class="header-anchor" href="#incremental-scans-and-watching" aria-label="Permalink to &quot;Incremental scans and watching&quot;">​</a></h2><p>The project includes a chokidar watcher for development. It batches changes with a <code>700ms</code> debounce window and chooses between:</p><ul><li>a full rescan for directory add/remove events</li><li>an incremental scan for file-level changes</li></ul><p>The watcher is not part of request handling, and request handlers never scan the filesystem directly.</p><h2 id="feed-behavior" tabindex="-1">Feed behavior <a class="header-anchor" href="#feed-behavior" aria-label="Permalink to &quot;Feed behavior&quot;">​</a></h2><p>The home feed supports three modes:</p><table tabindex="0"><thead><tr><th>Mode</th><th>Behavior</th></tr></thead><tbody><tr><td><code>recent</code></td><td>Uses <code>taken_at</code> when available, otherwise <code>sort_timestamp</code>, then diversifies bursts from the same folder.</td></tr><tr><td><code>rediscover</code></td><td>Surfaces posts older than 180 days and prioritizes liked items within that older pool.</td></tr><tr><td><code>random</code></td><td>Uses a deterministic seeded shuffle so a browsing session stays stable while paging.</td></tr></tbody></table><h2 id="reels-behavior" tabindex="-1">Reels behavior <a class="header-anchor" href="#reels-behavior" aria-label="Permalink to &quot;Reels behavior&quot;">​</a></h2><p>The <code>/reels</code> route reads only indexed video candidates from SQLite. It does not scan the filesystem on request.</p><p>The page opens with the app-wide default configured in Settings and does not provide an inline mode switch of its own.</p><table tabindex="0"><thead><tr><th>Mode</th><th>Behavior</th></tr></thead><tbody><tr><td><code>recommended</code></td><td>Builds a seeded queue from indexed videos using freshness, likes, folder-affinity signals from recent navigation, portrait fit, duration fit, and a small deterministic jitter. It also penalizes immediate repeats from the same folder when alternatives exist.</td></tr><tr><td><code>recent</code></td><td>Uses newest indexed videos first.</td></tr><tr><td><code>random</code></td><td>Uses a deterministic seeded shuffle so the queue stays stable while paging.</td></tr></tbody></table><h2 id="moments-and-highlights" tabindex="-1">Moments and highlights <a class="header-anchor" href="#moments-and-highlights" aria-label="Permalink to &quot;Moments and highlights&quot;">​</a></h2><p><code>GET /api/feed/moments</code> can return either Moments or Highlights.</p><h3 id="moments" tabindex="-1">Moments <a class="header-anchor" href="#moments" aria-label="Permalink to &quot;Moments&quot;">​</a></h3><p>Foldergram prefers date-based moments when the library has enough EXIF-backed timestamps:</p><ul><li>at least <code>24</code> indexed posts</li><li>at least <code>18</code> posts with <code>taken_at_source = &#39;exif&#39;</code></li><li>at least <code>30%</code> EXIF coverage</li></ul><p>The current date-driven capsules are:</p><ul><li>On This Day</li><li>This Week</li><li>Last Year Around Now</li></ul><h3 id="highlights" tabindex="-1">Highlights <a class="header-anchor" href="#highlights" aria-label="Permalink to &quot;Highlights&quot;">​</a></h3><p>When date coverage is too sparse, Foldergram falls back to curated sets:</p><ul><li>Recent Batches</li><li>Forgotten Favorites</li><li>Deep Cuts</li><li>Lucky Dip</li></ul><h2 id="folder-stories" tabindex="-1">Folder stories <a class="header-anchor" href="#folder-stories" aria-label="Permalink to &quot;Folder stories&quot;">​</a></h2><p>Folder stories use separate SQLite-backed queries from <code>GET /api/feed/moments</code>.</p><ul><li>folder summaries expose whether a folder currently has an avatar-story entry point</li><li><code>GET /api/folders/:slug/stories</code> returns the folder&#39;s avatar story and highlight capsules</li><li><code>GET /api/folders/:slug/stories/:id</code> pages through the media for one story capsule</li><li>neither route walks the filesystem on request</li></ul><h2 id="folder-rebuild-requirement" tabindex="-1">Folder rebuild requirement <a class="header-anchor" href="#folder-rebuild-requirement" aria-label="Permalink to &quot;Folder rebuild requirement&quot;">​</a></h2><p>Foldergram tracks the last successful gallery root. If that path changes and there is already indexed content, the scanner marks the library as requiring a rebuild. This is meant to prevent silent cross-library drift in the index and cached derivatives.</p><h2 id="derivative-migration-and-move-preservation" tabindex="-1">Derivative migration and move preservation <a class="header-anchor" href="#derivative-migration-and-move-preservation" aria-label="Permalink to &quot;Derivative migration and move preservation&quot;">​</a></h2><p>On upgraded libraries, the next full scan backfills <code>asset_key</code> values and moves stored derivatives from the legacy mirrored layout into the new sharded layout. The migration only rewrites stored derivative paths when the new target already exists, and it repairs surviving legacy files before falling back to regeneration. After that migration is complete, full rescans can reconcile safe file moves by matching size, rounded mtime, and extension, with a basename tie-break when needed. When reconciliation succeeds, the original row ID, likes, <code>sort_timestamp</code>, and derivative paths are preserved.</p><h2 id="runtime-read-model" tabindex="-1">Runtime read model <a class="header-anchor" href="#runtime-read-model" aria-label="Permalink to &quot;Runtime read model&quot;">​</a></h2><p>Once data is indexed:</p><ul><li>folder pages read from SQLite</li><li>feed pages read from SQLite</li><li>likes read from SQLite</li><li>moments, highlights, and folder stories read from SQLite</li><li>thumbnails and previews are served as static files</li><li>originals are served by image ID only</li></ul>`,78)])])}const m=a(s,[["render",o]]);export{u as __pageData,m as default};
